onRowSelected:
{{
(function() {
	const selectedRows = Table2.selectedRows || [];
	const selectedIds = selectedRows.map(r => r._id);

	csvImport.state.previewData.forEach(row => {
		row._selected = selectedIds.includes(row._id);
	});
})()
}}

